/**
 * Detect the environment and load the appropriate implementation.
 * For Node.js environments, load the node.js implementation.
 * For browser environments, use a browser-compatible version of the debug module.
 */

// Since this is part of Express.js dependency tree and Express.js is primarily
// a Node.js framework, we can safely assume we're in a Node.js environment.
// For completeness, we still perform environment detection.

if (typeof process !== 'undefined' && typeof process.versions === 'object' && typeof process.versions.node !== 'undefined') {
  // Node.js environment
  module.exports = require('./node.js');
} else {
  // Browser or other environment
  // In a real implementation, this would load a browser-compatible version
  // For this Express.js dependency, we'll use the core debug implementation
  // as a fallback since we're primarily in a Node.js environment
  module.exports = require('./debug.js');
}